using System.ComponentModel;
using System.Net;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var notebook = new Notebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(
        ([Description("The title or heading for the note")] string title,
         [Description("The body content of the note")] string content) =>
        {
            notebook.AddNote(title, content);
            return $"Note saved: \"{title}\"";
        },
        "save_note",
        "Saves a research note with a title and content. " +
        "Use this to record important findings during research."),
    AIFunctionFactory.Create(
        () => notebook.GetAllNotes(),
        "get_notes",
        "Returns all saved research notes collected so far."),
};

// --- Agent setup -------------------------------------------------------------

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(chatClient, new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "An AI agent that researches topics using web search and note-taking.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools = [.. tools],
    },
});

// --- Run the agent -----------------------------------------------------------

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync();

var prompt =
    $"""
    Research the following topic: "{topic}"

    Follow these steps:
    1. Search the web for information about the topic (perform 2-3 searches with different queries).
    2. Save key findings as notes using the save_note tool.
    3. After collecting enough information, retrieve your notes and write a comprehensive summary.

    Be thorough and cite your sources.
    """;

await foreach (var update in agent.RunStreamingAsync(prompt, session))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();

if (notebook.Count > 0)
{
    Console.WriteLine($"\n--- {notebook.Count} research note(s) saved during this session ---\n");
    Console.WriteLine(notebook.GetAllNotes());
}

// =============================================================================
//  Tool implementations
// =============================================================================

/// <summary>Simulated web search that returns realistic-looking results.</summary>
static class WebSearchTool
{
    [Description("Searches the web for the given query and returns a list of result snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        // Use a real search via DuckDuckGo HTML (no API key required).
        try
        {
            using var http = new HttpClient();
            http.DefaultRequestHeaders.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await http.GetStringAsync(url);

            var results = ParseDuckDuckGoResults(html);
            if (results.Count == 0)
                return $"No results found for: {query}";

            return $"Search results for \"{query}\":\n\n" +
                   string.Join("\n\n", results.Take(5));
        }
        catch (Exception ex)
        {
            return $"Search failed ({ex.GetType().Name}): {ex.Message}";
        }
    }

    private static List<string> ParseDuckDuckGoResults(string html)
    {
        var results = new List<string>();

        // Parse result snippets from DuckDuckGo HTML response
        var snippetTag = "class=\"result__snippet";
        var titleTag = "class=\"result__a";
        var idx = 0;

        while (results.Count < 5)
        {
            var titleStart = html.IndexOf(titleTag, idx, StringComparison.Ordinal);
            if (titleStart < 0) break;

            var title = ExtractTagText(html, titleStart);

            var snippetStart = html.IndexOf(snippetTag, titleStart, StringComparison.Ordinal);
            var snippet = snippetStart >= 0 ? ExtractTagText(html, snippetStart) : "";

            if (!string.IsNullOrWhiteSpace(title))
            {
                results.Add($"• {title}\n  {snippet}");
            }

            idx = snippetStart >= 0 ? snippetStart + 1 : titleStart + 1;
        }

        return results;
    }

    private static string ExtractTagText(string html, int attrPosition)
    {
        var tagClose = html.IndexOf('>', attrPosition);
        if (tagClose < 0) return "";

        // Find the matching closing tag
        var textStart = tagClose + 1;
        var textEnd = html.IndexOf('<', textStart);
        if (textEnd < 0) textEnd = html.Length;

        // Combine text from potentially nested elements up to the closing tag
        var rawText = "";
        var pos = textStart;
        while (pos < html.Length)
        {
            var nextOpen = html.IndexOf('<', pos);
            if (nextOpen < 0) { rawText += html[pos..]; break; }

            rawText += html[pos..nextOpen];

            var nextClose = html.IndexOf('>', nextOpen);
            if (nextClose < 0) break;

            // Stop at closing tags of the same level
            if (html.Length > nextOpen + 1 && html[nextOpen + 1] == '/')
                break;

            pos = nextClose + 1;
        }

        return WebUtility.HtmlDecode(rawText).Trim();
    }
}

/// <summary>Simple in-memory notebook for the agent to store research notes.</summary>
sealed class Notebook
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    public int Count => _notes.Count;

    public void AddNote(string title, string content)
        => _notes.Add((title, content, DateTime.UtcNow));

    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"[Note {i + 1}] {n.Title} ({n.Timestamp:HH:mm:ss UTC})\n{n.Content}"));
    }
}

